const ROLES = ['Employee', 'Manager', 'Finance', 'Director'];
const STATUS_COLOR = { Pending: '#f59e0b', Approved: '#10b981', Rejected: '#ef4444' };

export default function AdminDashboard() {
  const { user, logout } = useAuth();
  const [tab, setTab] = useState('users');
  const [users, setUsers] = useState([]);
  const [expenses, setExpenses] = useState([]);
  const [rules, setRules] = useState([]);
  const [newUser, setNewUser] = useState({ name: '', email: '', password: '', role: 'Employee', managerId: '' });
  const [newRule, setNewRule] = useState({ name: '', type: 'percentage', percentage: '', specificApproverId: '', hybridOperator: 'OR' });
  const [error, setError] = useState('');

  useEffect(() => {
    api.get('/users').then((r) => setUsers(r.data));
    api.get('/expenses').then((r) => setExpenses(r.data));
    api.get('/rules').then((r) => setRules(r.data));
  }, []);

  const createUser = async (e) => {
    e.preventDefault();
    setError('');
    try {
      const res = await api.post('/users', newUser);
      setUsers([...users, res.data]);
      setNewUser({ name: '', email: '', password: '', role: 'Employee', managerId: '' });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to create user');
    }
  };

  const deleteUser = async (id) => {
    if (!window.confirm('Delete this user?')) return;
    await api.delete(`/users/${id}`);
    setUsers(users.filter((u) => u._id !== id));
  };

  const createRule = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/rules', newRule);
      setRules([...rules, res.data]);
      setNewRule({ name: '', type: 'percentage', percentage: '', specificApproverId: '', hybridOperator: 'OR' });
    } catch (err) {
      alert(err.response?.data?.message || 'Failed to create rule');
    }
  };

  const deleteRule = async (id) => {
    await api.delete(`/rules/${id}`);
    setRules(rules.filter((r) => r._id !== id));
  };

  const overrideExpense = async (id, status) => {
    await api.put(`/expenses/${id}/override`, { status });
    const res = await api.get('/expenses');
    setExpenses(res.data);
  };

  const managers = users.filter((u) => u.role === 'Manager');

  return (
    <div style={styles.page}>
      <header style={styles.header}>
        <h2>Admin Dashboard</h2>
        <button style={styles.btnLogout} onClick={logout}>Logout</button>
      </header>
      <p>Welcome, {user?.name}</p>

      <div style={styles.tabs}>
        {['users', 'expenses', 'rules'].map((t) => (
          <button key={t} style={{ ...styles.tab, ...(tab === t ? styles.activeTab : {}) }} onClick={() => setTab(t)}>
            {t.charAt(0).toUpperCase() + t.slice(1)}
          </button>
        ))}
      </div>

      {/* USERS TAB */}
      {tab === 'users' && (
        <div>
          <h3>Create User</h3>
          {error && <p style={{ color: 'red' }}>{error}</p>}
          <form onSubmit={createUser} style={styles.form}>
            <input style={styles.input} placeholder="Name" required value={newUser.name} onChange={(e) => setNewUser({ ...newUser, name: e.target.value })} />
            <input style={styles.input} placeholder="Email" type="email" required value={newUser.email} onChange={(e) => setNewUser({ ...newUser, email: e.target.value })} />
            <input style={styles.input} placeholder="Password" type="password" required value={newUser.password} onChange={(e) => setNewUser({ ...newUser, password: e.target.value })} />
            <select style={styles.input} value={newUser.role} onChange={(e) => setNewUser({ ...newUser, role: e.target.value })}>
              {ROLES.map((r) => <option key={r}>{r}</option>)}
            </select>
            <select style={styles.input} value={newUser.managerId} onChange={(e) => setNewUser({ ...newUser, managerId: e.target.value })}>
              <option value="">No Manager</option>
              {managers.map((m) => <option key={m._id} value={m._id}>{m.name}</option>)}
            </select>
            <button style={styles.btnPrimary} type="submit">Create</button>
          </form>
          <h3>All Users</h3>
          <table style={styles.table}>
            <thead><tr>{['Name', 'Email', 'Role', 'Manager', 'Action'].map((h) => <th key={h} style={styles.th}>{h}</th>)}</tr></thead>
            <tbody>
              {users.map((u) => (
                <tr key={u._id}>
                  <td style={styles.td}>{u.name}</td>
                  <td style={styles.td}>{u.email}</td>
                  <td style={styles.td}>{u.role}</td>
                  <td style={styles.td}>{u.manager?.name || '—'}</td>
                  <td style={styles.td}><button style={styles.btnDanger} onClick={() => deleteUser(u._id)}>Delete</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* EXPENSES TAB */}
      {tab === 'expenses' && (
        <div>
          <h3>All Expenses</h3>
          <table style={styles.table}>
            <thead><tr>{['Employee', 'Category', 'Amount', 'Status', 'Override'].map((h) => <th key={h} style={styles.th}>{h}</th>)}</tr></thead>
            <tbody>
              {expenses.map((e) => (
                <tr key={e._id}>
                  <td style={styles.td}>{e.employee?.name}</td>
                  <td style={styles.td}>{e.category}</td>
                  <td style={styles.td}>{e.amount} {e.currency}</td>
                  <td style={styles.td}><span style={{ color: STATUS_COLOR[e.status] }}>{e.status}</span></td>
                  <td style={styles.td}>
                    <button style={{ ...styles.btnPrimary, marginRight: '0.3rem', padding: '0.3rem 0.6rem' }} onClick={() => overrideExpense(e._id, 'Approved')}>Approve</button>
                    <button style={{ ...styles.btnDanger, padding: '0.3rem 0.6rem' }} onClick={() => overrideExpense(e._id, 'Rejected')}>Reject</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* RULES TAB */}
      {tab === 'rules' && (
        <div>
          <h3>Create Rule</h3>
          <form onSubmit={createRule} style={styles.form}>
            <input style={styles.input} placeholder="Rule Name" required value={newRule.name} onChange={(e) => setNewRule({ ...newRule, name: e.target.value })} />
            <select style={styles.input} value={newRule.type} onChange={(e) => setNewRule({ ...newRule, type: e.target.value })}>
              <option value="percentage">Percentage</option>
              <option value="specific_approver">Specific Approver</option>
              <option value="hybrid">Hybrid</option>
            </select>
            {(newRule.type === 'percentage' || newRule.type === 'hybrid') && (
              <input style={styles.input} type="number" step="0.01" min="0" max="1" placeholder="Percentage (0.0 - 1.0)" value={newRule.percentage} onChange={(e) => setNewRule({ ...newRule, percentage: e.target.value })} />
            )}
            {(newRule.type === 'specific_approver' || newRule.type === 'hybrid') && (
              <select style={styles.input} value={newRule.specificApproverId} onChange={(e) => setNewRule({ ...newRule, specificApproverId: e.target.value })}>
                <option value="">Select Approver</option>
                {users.map((u) => <option key={u._id} value={u._id}>{u.name} ({u.role})</option>)}
              </select>
            )}
            {newRule.type === 'hybrid' && (
              <select style={styles.input} value={newRule.hybridOperator} onChange={(e) => setNewRule({ ...newRule, hybridOperator: e.target.value })}>
                <option value="OR">OR</option>
                <option value="AND">AND</option>
              </select>
            )}
            <button style={styles.btnPrimary} type="submit">Create Rule</button>
          </form>
          <h3>Active Rules</h3>
          {rules.map((r) => (
            <div key={r._id} style={styles.ruleCard}>
              <strong>{r.name}</strong> — {r.type}
              {r.percentage != null && ` | ${(r.percentage * 100).toFixed(0)}%`}
              {r.specificApproverId && ` | Approver: ${r.specificApproverId.name || r.specificApproverId}`}
              {r.hybridOperator && ` | ${r.hybridOperator}`}
              <button style={{ ...styles.btnDanger, marginLeft: '1rem', padding: '0.2rem 0.6rem' }} onClick={() => deleteRule(r._id)}>Delete</button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

const styles = {
  page: { maxWidth: '1000px', margin: '2rem auto', padding: '0 1rem' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  tabs: { display: 'flex', gap: '0.5rem', marginBottom: '1.5rem', borderBottom: '2px solid #e5e7eb', paddingBottom: '0.5rem' },
  tab: { padding: '0.5rem 1.2rem', border: 'none', background: 'none', cursor: 'pointer', borderRadius: '4px', fontSize: '1rem' },
  activeTab: { background: '#4f46e5', color: '#fff' },
  form: { display: 'flex', flexWrap: 'wrap', gap: '0.5rem', marginBottom: '1.5rem', alignItems: 'center' },
  input: { padding: '0.5rem', borderRadius: '4px', border: '1px solid #ccc', minWidth: '160px' },
  table: { width: '100%', borderCollapse: 'collapse', marginBottom: '1.5rem' },
  th: { background: '#f3f4f6', padding: '0.6rem', textAlign: 'left', borderBottom: '1px solid #e5e7eb' },
  td: { padding: '0.6rem', borderBottom: '1px solid #e5e7eb' },
  btnPrimary: { padding: '0.5rem 1rem', background: '#4f46e5', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  btnDanger: { padding: '0.5rem 1rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  btnLogout: { padding: '0.5rem 1rem', background: '#ef4444', color: '#fff', border: 'none', borderRadius: '4px', cursor: 'pointer' },
  ruleCard: { background: '#f9fafb', border: '1px solid #e5e7eb', borderRadius: '4px', padding: '0.75rem', marginBottom: '0.5rem' },
};
